## Test Template

```typescript
// src/components/education/knowledge-hub/renderers/index.test.tsx
import { describe, it, expect } from 'vitest';
import { hasRenderer, getSupportedRenderers, getRendererImport } from './index';
import type { ToolType } from '@/types';

describe('Renderer Registry', () => {
  it('should have renderers for all 12 tool types', () => {
    const supported = getSupportedRenderers();
    expect(supported).toHaveLength(12);
  });

  it('should return true for existing renderer', () => {
    expect(hasRenderer('mindmap')).toBe(true);
  });

  it('should return false for non-existent renderer', () => {
    expect(hasRenderer('invalid' as ToolType)).toBe(false);
  });

  it('should return renderer for valid type', () => {
    const renderer = getRendererImport('mindmap');
    expect(renderer).toBeDefined();
  });

  it('should return null for invalid type', () => {
    const renderer = getRendererImport('invalid' as ToolType);
    expect(renderer).toBeNull();
  });
});
```

